#include <bits/stdc++.h>
using namespace std;

int T,n,p,sqi;

struct Node{
    int a,b;
    Node operator*(Node x)const{
        Node res;
        res.a=(1ll*a*x.a+1ll*b*x.b%p*sqi)%p;
        res.b=(1ll*a*x.b+1ll*b*x.a)%p;
        return res;
    }
};

int qpow(int a,int b){
    long long ans=1,base=(a+p)%p;
    while(b){
        if(b&1)
            ans=ans*base%p;
        base=base*base%p,b>>=1;
    }
    return ans;
}

int exqpow(int a,int b){
    Node ans={1,0},base={a,1};
    while(b){
        if(b&1)
            ans=ans*base;
        base=base*base,b>>=1;
    }
    return ans.a;
}

int main(){
    srand(time(NULL));
    scanf("%d",&T);
    while(T--){
        scanf("%d%d",&n,&p);
        n%=p;
        if(n==0){
            puts("0");
            continue;
        }
        if(qpow(n,(p-1)/2)==p-1){
            puts("Hola!");
            continue;
        }
        int a=rand()%p;
        while(qpow((1ll*a*a-n)%p,(p-1)/2)==1)
            a=rand()%p;
        sqi=((1ll*a*a-n)%p+p)%p;
        int ans=exqpow(a,(p+1)/2);
        ans=min(ans,p-ans);
        printf("%d %d\n",ans,p-ans);
    }
    return 0;
}
